factory.logic:
let _instance = null;
export function getStorageProvider() {
  if (_instance) return _instance;
  switch (process.env.STORAGE_PROVIDER) {
    case 'supabase': _instance = new SupabaseStorageProvider(); break;
    case 'azure':    _instance = new AzureStorageProvider();    break;
    default: throw new Error('Unknown STORAGE_PROVIDER: ' + process.env.STORAGE_PROVIDER);
  }
  return _instance;
}

item.config:
multer({ storage: multer.memoryStorage(),
         limits: { fileSize: UPLOAD_MAX_SIZE_MB * 1024 * 1024 },
         fileFilter: (req, file, cb) => {
           const allowed = UPLOAD_ALLOWED_TYPES.split(",");
           cb(null, allowed.includes(file.mimetype));
         }
       })

item.logic:
(err, req, res, next) =>
  if err instanceof AppError: res.status(err.httpStatus).json({ success:false, error:{ code:err.code, message:err.message } })
  else: log full error internally; res.status(500).json({ success:false, error:{ code:"ERR_INTERNAL", message:"Internal server error" } })
  (stack trace NEVER sent to client in production)

