procedure.body:
START TRANSACTION;
  UPDATE applications SET status=aprobada, approved_at=NOW(), approver_admin_id=p_admin_id WHERE id=p_application_id;
  SET @collab_id = (SELECT collaborator_id FROM applications WHERE id=p_application_id);
  SET @proj_id   = (SELECT project_id FROM applications WHERE id=p_application_id);
  INSERT INTO assignments (collaborator_id, project_id, application_id, assigned_by_admin_id, status, assigned_at)
    VALUES (@collab_id, @proj_id, p_application_id, p_admin_id, activo, NOW());
  UPDATE projects SET current_collaborator_count = current_collaborator_count + 1 WHERE id=@proj_id;
  UPDATE collaborators SET trajectory_status=vinculado, updated_at=NOW() WHERE id=@collab_id;
COMMIT;

START TRANSACTION;
  INSERT INTO collaborators (...) VALUES (...);
  SET @new_id = LAST_INSERT_ID();
  -- tag insertions handled by application layer (not in SP for flexibility)
COMMIT;
SELECT @new_id as id;
